SELECT average_execution_time AS avg_execution_time
FROM operator_history
WHERE operator_id = 0;

SELECT operator_id
FROM operator_history
WHERE usage_count = (SELECT MAX(usage_count) FROM operator_history);

SELECT AVG(rating) AS average_rating
FROM operation_feedback
WHERE rating <= 3;

SELECT operator_id
FROM operator_usage
WHERE usage_count > 10 AND average_execution_time > 0.1;

SELECT SUM(usage_count) AS total_usage
FROM operator_usage
WHERE user_id = 0 AND operator_id = 0;

SELECT AVG(execution_time) AS average_execution_time
FROM operations
WHERE user_id = 0;

SELECT operator_id, usage_count
FROM operator_history
ORDER BY usage_count DESC;
